prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  FILTER(?model = <https://www.teamingai-project.eu/model/4ccc3fd711004f519782ac92e58f6ddd> || 
         ?model = <http://www.onto-bpo.eu/ontologies/bboExtension#4ccc3fd711004f519782ac92e58f6ddd>)
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?originalId)), "4ccc3fd711004f519782ac92e58f6ddd") ||
         CONTAINS(LCASE(STR(?normalizedId)), "4ccc3fd711004f519782ac92e58f6ddd") ||
         CONTAINS(LCASE(STR(?model)), "4ccc3fd711004f519782ac92e58f6ddd"))
}
LIMIT 25
